const caseData = $items("Fetch Full Case")[0]?.json ?? {};
const policies = ($items("Fetch Policies") || []).map((i) => i.json);
const webhookBody = $node["Webhook Trigger"]?.json?.body ?? {};

const normalize = (value) => String(value ?? "").trim().toLowerCase() || null;
const toArray = (value) => (Array.isArray(value) ? value : []);
const toNumber = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
};

const dispute_type = normalize(caseData.dispute_type ?? webhookBody.dispute_type);
const dispute_subtype = normalize(caseData.dispute_subtype ?? webhookBody.dispute_subtype);
const resolution_preference = normalize(
  caseData.resolution_preference ?? webhookBody.resolution_preference
);

const case_status = normalize(caseData.status);
const invalid_reason_code = normalize(caseData.invalid_reason_code);
const invalid_reason_detail = caseData.invalid_reason_detail ?? null;
const appeal_priority = normalize(caseData.appeal_priority);

const bundle = caseData.information_bundle ?? {};

const orderFromOrder = bundle.order ?? null;
const orderFromOrderData = bundle.order_data
  ? {
      order_id: bundle.order_data.order_id ?? null,
      status: bundle.order_data.order_status ?? null,
      created_at: bundle.order_data.order_date ?? null,
      fulfilled_at: bundle.order_data.fulfilled_at ?? null,
      delivered_at: bundle.order_data.delivered_at ?? null,
      total_amount: bundle.order_data.total_amount ?? null,
      customer_email: bundle.order_data.customer_email ?? null,
    }
  : null;

const order = orderFromOrder ?? orderFromOrderData ?? null;

const paymentRecords = toArray(bundle.payment_records);
const paymentTxnFromRecords =
  paymentRecords.find((p) => normalize(p.transaction_type) === "payment") ?? null;

const transaction = bundle.transaction ?? paymentTxnFromRecords ?? null;

const refundRecordsFromBundle = toArray(bundle.refund_records);
const refundRecordsFromPayment = paymentRecords.filter(
  (p) => normalize(p.transaction_type) === "refund"
);
const refundRecords =
  refundRecordsFromBundle.length > 0 ? refundRecordsFromBundle : refundRecordsFromPayment;

const shipment = bundle.shipment ?? bundle.shipment_data ?? null;
const trackingEvents = toArray(bundle.tracking_events);
const stockRecords = toArray(bundle.stock_records);
const orderItemsDetail = toArray(bundle.order_items_detail);
const affected_item_ids = toArray(bundle.affected_item_ids);
const affected_items_detail = toArray(bundle.affected_items_detail);

const proof_requirements = bundle.proof_requirements ?? caseData.proof_requirements ?? null;
const proof_uploads = toArray(bundle.proof_uploads ?? caseData.proof_uploads);
const proof_analysis = bundle.proof_analysis ?? caseData.proof_analysis ?? null;
const proof_analysis_status =
  bundle.proof_analysis_status ?? caseData.proof_analysis_status ?? null;
const evidence_bundle = bundle.evidence_bundle ?? caseData.evidence_bundle ?? null;
const proof_messages = toArray(bundle.proof_messages);
const proof_attachments = toArray(bundle.proof_attachments);
const intake_messages = toArray(bundle.intake_messages);
const recent_transcript = toArray(bundle.recent_transcript);

const current_date = new Date().toISOString().split("T")[0];

const toDateOnly = (value) => {
  if (!value || typeof value !== "string") return null;
  return value.includes("T") ? value.split("T")[0] : value;
};

const diffDaysUtc = (fromDate, toDate) => {
  if (!fromDate || !toDate) return null;
  const from = new Date(`${fromDate}T00:00:00Z`);
  const to = new Date(`${toDate}T00:00:00Z`);
  if (Number.isNaN(from.getTime()) || Number.isNaN(to.getTime())) return null;
  return Math.floor((to.getTime() - from.getTime()) / 86400000);
};

const delivered_date = toDateOnly(
  shipment?.delivered_at ??
    bundle?.shipment_data?.delivered_at ??
    order?.delivered_at ??
    bundle?.order_data?.delivered_at ??
    null
);

const fulfilled_date = toDateOnly(
  order?.fulfilled_at ??
    bundle?.order_data?.fulfilled_at ??
    null
);

const order_created_date = toDateOnly(
  order?.created_at ??
    bundle?.order_data?.order_date ??
    null
);

const return_window_basis_date = delivered_date ?? fulfilled_date ?? order_created_date;

const days_since_basis_date =
  return_window_basis_date != null
    ? diffDaysUtc(return_window_basis_date, current_date)
    : null;

const transaction_amount = toNumber(
  transaction?.amount ??
    bundle?.order_data?.total_amount ??
    order?.total_amount
);

const hasInventorySnapshot =
  stockRecords.length > 0 ||
  orderItemsDetail.some((i) => i.quantity_available_now != null);

const anyItemOutOfStock = orderItemsDetail.some((i) => {
  const available = toNumber(i.quantity_available_now);
  const ordered = toNumber(i.quantity_ordered);
  if (available == null || ordered == null) return true;
  return available < ordered;
});

const itemsMissingInventoryData = orderItemsDetail.some((i) => {
  return i.quantity_available_now == null;
});

const proofPresent =
  proof_uploads.length > 0 ||
  evidence_bundle?.proof_present === true ||
  proof_attachments.length > 0;

const proofFacts = {
  proof_required: proof_requirements?.required === true,
  proof_present: proofPresent,
  proof_upload_count: proof_uploads.length,
  proof_uploads,
  proof_analysis,
  proof_analysis_status,
  evidence_bundle,
  proof_messages,
  proof_attachments,
};

const refundFacts = {
  payment_status: transaction?.status ?? null,
  order_status: order?.status ?? null,
  transaction_amount,
  amount_threshold: 500,
  refund_record_count: refundRecords.length,
  delivered_date,
  fulfilled_date,
  order_created_date,
  return_window_basis_date,
  days_since_basis_date,
  within_return_window:
    days_since_basis_date != null
      ? days_since_basis_date >= 0 && days_since_basis_date <= 7
      : null,
};

const deliveryFacts = {
  shipment_status: shipment?.status ?? null,
  shipped_at: shipment?.shipped_at ?? null,
  delivered_at: shipment?.delivered_at ?? bundle?.shipment_data?.delivered_at ?? null,
  estimated_delivery: shipment?.estimated_delivery ?? null,
  tracking_event_count: trackingEvents.length,
  tracking_events: trackingEvents,
  current_date,
};

const replacementFacts = {
  resolution_preference,
  has_inventory_snapshot: hasInventorySnapshot,
  any_item_out_of_stock: anyItemOutOfStock,
  items_missing_inventory_data: itemsMissingInventoryData,
  order_items_detail_count: orderItemsDetail.length,
};

const returnFacts = {
  resolution_preference,
  delivered_date,
  fulfilled_date,
  order_created_date,
  return_window_basis_date,
  days_since_basis_date,
  within_return_window:
    days_since_basis_date != null
      ? days_since_basis_date >= 0 && days_since_basis_date <= 7
      : null,
};

const matrixRules = [
  "ROAR_WF_Manual_Mapping_Guide_Decision_Matrix.md is the source of truth.",
  "Use canonical dispute_subtype and resolution_preference from the case record.",
  "resolution_preference is customer-requested; resolution_type is triage-decided.",
  "Apply global blockers before subtype-specific routing.",
  "Duplicate refund risk escalates refund cases.",
  "Unconfirmed payment blocks autonomous or approval routing and requires escalation.",
  "Delivered-but-disputed delivery cases escalate.",
  "Autonomous threshold is THB 500 for refunds and replacements.",
  "Returns are never autonomous.",
  "Return/refund policy window is 7 days.",
  "Replacement requires inventory availability.",
  "affected_items_detail is additive and important for replacement and partial-item logic.",
  "Image proof supports triage facts but does not override deterministic policy.",
  "If a case is invalid/ineligible or lacks sufficient supporting proof, prefer awaiting_customer_decision over immediate human escalation unless the matrix explicitly requires human review.",
];

const expectedDecisionModel = {
  allowed_case_status_outcomes: [
    "approved_executing",
    "awaiting_approval",
    "escalated_human_required",
    "awaiting_customer_decision",
  ],
  allowed_resolution_types: [
    "refund",
    "replacement",
    "return",
    null,
  ],
};

const user_message = {
  case: {
    id: caseData.id ?? webhookBody.case_id ?? null,
    status: case_status,
    dispute_type,
    dispute_subtype,
    resolution_preference,
    invalid_reason_code,
    invalid_reason_detail,
    appeal_priority,
  },
  information_bundle: bundle || null,
  proof_context: proofFacts,
  policy_context: policies,
  triage_rules: matrixRules,
  expected_decision_model: expectedDecisionModel,
  current_date,
  facts: {
    refund: refundFacts,
    delivery: deliveryFacts,
    replacement: replacementFacts,
    return: returnFacts,
    proof: proofFacts,
    affected_items: {
      affected_item_ids,
      affected_items_detail,
      order_items_detail,
    },
  },
  transcript_context: {
    intake_messages,
    recent_transcript,
  },
};

return [
  {
    case_id: caseData.id ?? webhookBody.case_id ?? null,
    dispute_type,
    dispute_subtype,
    resolution_preference,
    user_message,
  },
];

const input = $input.first().json || {};

const topCaseId = input.case_id ?? null;
const topDisputeType = input.dispute_type ?? null;
const topDisputeSubtype = input.dispute_subtype ?? null;
const topResolutionPreference = input.resolution_preference ?? null;

const userMessage = input.user_message || {};
const bundle = userMessage.information_bundle || input.information_bundle || {};
const facts = userMessage.facts || input.facts || {};
const caseCtx = userMessage.case || {};

const caseData = {
  case_id: topCaseId ?? caseCtx.id ?? null,
  status: caseCtx.status ?? null,
  dispute_type: topDisputeType ?? caseCtx.dispute_type ?? null,
  dispute_subtype: topDisputeSubtype ?? caseCtx.dispute_subtype ?? null,
  resolution_preference: topResolutionPreference ?? caseCtx.resolution_preference ?? null,
  invalid_reason_code: caseCtx.invalid_reason_code ?? null,
  invalid_reason_detail: caseCtx.invalid_reason_detail ?? null,
};

const AUTONOMOUS_REFUND_THRESHOLD = 500.0;
const AUTONOMOUS_REPLACEMENT_THRESHOLD = 500.0;
const RETURN_WINDOW_DAYS = 7;

const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const normalize = (v) => String(v || "").trim().toLowerCase();

const parseDate = (v) => {
  if (!v) return null;
  const d = new Date(v);
  return Number.isNaN(d.getTime()) ? null : d;
};

const daysSince = (dateLike) => {
  const d = parseDate(dateLike);
  if (!d) return null;
  const now = new Date();
  const ms = now.getTime() - d.getTime();
  return Math.floor(ms / (1000 * 60 * 60 * 24));
};

const daysBetween = (fromLike, toLike) => {
  const from = parseDate(fromLike);
  const to = parseDate(toLike);
  if (!from || !to) return null;
  const ms = to.getTime() - from.getTime();
  return Math.floor(ms / (1000 * 60 * 60 * 24));
};

const normalizeSubtype = (value) => {
  const raw = normalize(value);

  const aliases = {
    package_never_arrived: "non_receipt",
    delivery_late: "delayed",
    wrong_delivery_address: "exception",
    quality_issue: "not_as_described",
    return_for_refund: "return_request",
  };

  return aliases[raw] || raw;
};

const normalizeResolutionPreference = (value) => {
  const raw = normalize(value);
  return ["refund", "replacement", "return"].includes(raw) ? raw : null;
};

const getPaymentRecord = (paymentRecords = []) =>
  paymentRecords.find((p) => normalize(p.transaction_type) === "payment") || null;

const getRefundRecords = (paymentRecords = []) =>
  paymentRecords.filter((p) => normalize(p.transaction_type) === "refund");

const hasPriorRefund = (paymentRecords = []) => {
  const refunds = getRefundRecords(paymentRecords);
  const totalRefunded = refunds.reduce((sum, p) => sum + (toNum(p.amount) || 0), 0);

  return {
    exists: refunds.length > 0,
    count: refunds.length,
    totalRefunded,
  };
};

const getTrackingEvent = (trackingEvents = [], eventType) =>
  (Array.isArray(trackingEvents) ? trackingEvents : []).find(
    (e) => normalize(e.event_type) === normalize(eventType)
  ) || null;

const sumItemAmount = (items = []) => {
  if (!Array.isArray(items) || items.length === 0) return 0;

  return items.reduce((sum, item) => {
    const qty = toNum(item.quantity_ordered ?? item.quantity) ?? 0;
    const price = toNum(item.unit_price) ?? 0;
    return sum + qty * price;
  }, 0);
};

const checkInventory = (items = []) => {
  if (!Array.isArray(items) || items.length === 0) {
    return {
      feasible: false,
      reason: "Replacement requested but no affected order item inventory data is available",
    };
  }

  const blockedItems = items.filter((item) => {
    const available = toNum(item.quantity_available_now);
    const ordered = toNum(item.quantity_ordered ?? item.quantity);
    if (available == null || ordered == null) return true;
    return available < ordered;
  });

  if (blockedItems.length > 0) {
    const names = blockedItems
      .map((i) => i.product_name || i.item_id || "Unknown item")
      .join(", ");

    return {
      feasible: false,
      reason: `Replacement requested but inventory is insufficient or unknown for: ${names}`,
    };
  }

  return {
    feasible: true,
    reason: "All affected items have sufficient inventory",
  };
};

const allowedResolutionTypes = {
  duplicate_charge: new Set(["refund"]),
  not_as_described: new Set(["refund", "replacement"]),
  damaged_goods: new Set(["refund", "replacement"]),
  wrong_item: new Set(["refund", "replacement"]),
  partial_fulfillment: new Set(["refund"]),
  return_request: new Set(["return"]),
  changed_mind: new Set(["return"]),
  other: new Set(["refund"]),
  non_receipt: new Set(["refund", "replacement"]),
  delayed: new Set(["refund"]),
  exception: new Set(["refund"]),
  lost: new Set(["refund", "replacement"]),
};

const defaultResolutionTypeForSubtype = (subtype) => {
  if (subtype === "return_request" || subtype === "changed_mind") return "return";
  if (subtype === "duplicate_charge" || subtype === "partial_fulfillment" || subtype === "other") return "refund";
  if (subtype === "delayed" || subtype === "exception") return "refund";
  if (subtype === "non_receipt" || subtype === "lost") return "refund";
  return "refund";
};

const resolveResolutionType = (subtype, preference) => {
  const allowed = allowedResolutionTypes[subtype] || new Set(["refund"]);
  if (preference && allowed.has(preference)) return preference;
  const fallback = defaultResolutionTypeForSubtype(subtype);
  if (allowed.has(fallback)) return fallback;
  return [...allowed][0] || "refund";
};

const pickBool = (value, nestedKey = "detected") => {
  if (typeof value === "boolean") return value;
  if (value && typeof value === "object") {
    if (typeof value.visible === "boolean") return value.visible;
    if (typeof value[nestedKey] === "boolean") return value[nestedKey];
  }
  return null;
};

const makeDecision = ({
  triage_decision,
  resolution_type,
  reason,
  eligible_amount = null,
  requires_human_review,
  tracking_evidence = null,
  replacement_items = null,
  shipping_fee_refund_only = null,
  affected_item_ids = null,
  invalid_reason_code = null,
  invalid_reason_detail = null,
}) => {
  const json = {
    triage_decision,
    resolution_type,
    reason,
    eligible_amount,
    requires_human_review,
    case_id: caseData.case_id,
  };

  if (tracking_evidence) json.tracking_evidence = tracking_evidence;
  if (Array.isArray(replacement_items)) json.replacement_items = replacement_items;
  if (shipping_fee_refund_only === true) json.shipping_fee_refund_only = true;
  if (Array.isArray(affected_item_ids) && affected_item_ids.length > 0) json.affected_item_ids = affected_item_ids;
  if (invalid_reason_code) json.invalid_reason_code = invalid_reason_code;
  if (invalid_reason_detail) json.invalid_reason_detail = invalid_reason_detail;

  return [{ json }];
};

const approveExecuting = (payload) =>
  makeDecision({
    ...payload,
    triage_decision: "approved_executing",
    requires_human_review: false,
  });

const awaitApproval = (payload) =>
  makeDecision({
    ...payload,
    triage_decision: "awaiting_approval",
    requires_human_review: true,
  });

const escalateHuman = (payload) =>
  makeDecision({
    ...payload,
    triage_decision: "escalated_human_required",
    requires_human_review: true,
  });

const awaitCustomerDecision = (payload) =>
  makeDecision({
    ...payload,
    triage_decision: "awaiting_customer_decision",
    requires_human_review: false,
  });

// -----------------------------------------------------------------------------
// DATA EXTRACTION
// -----------------------------------------------------------------------------
const disputeSubtype = normalizeSubtype(caseData.dispute_subtype);
const requestedResolutionPreference = normalizeResolutionPreference(caseData.resolution_preference);
const resolvedResolutionType = resolveResolutionType(disputeSubtype, requestedResolutionPreference);

const orderData = bundle.order_data || bundle.order || {};
const shipmentData = bundle.shipment_data || bundle.shipment || {};
const paymentRecords = Array.isArray(bundle.payment_records) ? bundle.payment_records : [];
const trackingEvents = Array.isArray(bundle.tracking_events) ? bundle.tracking_events : [];
const orderItems = Array.isArray(bundle.order_items_detail) ? bundle.order_items_detail : [];
const affectedItems =
  Array.isArray(bundle.affected_items_detail) && bundle.affected_items_detail.length > 0
    ? bundle.affected_items_detail
    : orderItems;
const affectedItemIds = Array.isArray(bundle.affected_item_ids) ? bundle.affected_item_ids : [];

const refundFacts = facts.refund || {};
const deliveryFacts = facts.delivery || {};
const proofFacts = facts.proof || {};

const paymentRecord = getPaymentRecord(paymentRecords);
const priorRefund = hasPriorRefund(paymentRecords);

const paymentStatus = normalize(
  refundFacts.payment_status ||
  paymentRecord?.status ||
  null
);

const paymentConfirmed = ["confirmed", "completed", "paid", "success", "succeeded"].includes(paymentStatus);

const orderStatus = normalize(
  refundFacts.order_status ||
  orderData.order_status ||
  orderData.status ||
  null
);

const orderStatusEligible = ["fulfilled", "returned"].includes(orderStatus);

const totalOrderAmount =
  toNum(refundFacts.transaction_amount) ??
  toNum(orderData.total_amount) ??
  toNum(paymentRecord?.amount) ??
  0;

const affectedAmount =
  affectedItems.length > 0
    ? sumItemAmount(affectedItems)
    : totalOrderAmount;

const replacementAmount = affectedAmount || totalOrderAmount;

const shippingFee =
  toNum(orderData.shipping_fee) ??
  toNum(orderData.delivery_fee) ??
  0;

const deliveredEvent = getTrackingEvent(trackingEvents, "delivered");
const lostEvent = getTrackingEvent(trackingEvents, "lost");
const exceptionEvent =
  getTrackingEvent(trackingEvents, "exception") ||
  getTrackingEvent(trackingEvents, "delayed");
const inTransitEvent = getTrackingEvent(trackingEvents, "in_transit");

const windowBasis =
  shipmentData.delivered_at ||
  orderData.delivered_at ||
  orderData.fulfilled_at ||
  orderData.order_date ||
  deliveredEvent?.event_time ||
  null;

const daysWindow =
  typeof refundFacts.days_since_basis_date === "number"
    ? refundFacts.days_since_basis_date
    : daysSince(windowBasis);

const withinReturnWindow =
  typeof refundFacts.within_return_window === "boolean"
    ? refundFacts.within_return_window
    : (daysWindow != null ? daysWindow >= 0 && daysWindow <= RETURN_WINDOW_DAYS : false);

const inventoryCheck =
  resolvedResolutionType === "replacement"
    ? checkInventory(affectedItems)
    : { feasible: null, reason: null };

// -----------------------------------------------------------------------------
// PROOF FACTS
// -----------------------------------------------------------------------------
const proofRequired =
  proofFacts.proof_required === true ||
  bundle.proof_requirements?.required === true;

const proofUploads = Array.isArray(proofFacts.proof_uploads)
  ? proofFacts.proof_uploads
  : Array.isArray(bundle.proof_uploads)
    ? bundle.proof_uploads
    : [];

const proofPresent =
  proofFacts.proof_present === true ||
  proofUploads.length > 0 ||
  bundle.evidence_bundle?.proof_present === true;

const proofAnalysis =
  proofFacts.proof_analysis ||
  bundle.proof_analysis ||
  bundle.evidence_bundle?.proof_analysis ||
  null;

const proofAnalysisStatus =
  normalize(
    proofFacts.proof_analysis_status ||
    bundle.proof_analysis_status ||
    bundle.evidence_bundle?.proof_analysis_status ||
    null
  );

const damageDetected = pickBool(proofAnalysis?.damage_detected, "detected");
const wrongItemDetected = pickBool(proofAnalysis?.wrong_item_signals, "detected");
const missingItemDetected = pickBool(proofAnalysis?.missing_item_signals, "detected");
const notAsDescribedDetected = pickBool(proofAnalysis?.not_as_described_signals, "detected");

const proofSupportsSubtype = (() => {
  switch (disputeSubtype) {
    case "damaged_goods":
      return damageDetected === true;
    case "wrong_item":
      return wrongItemDetected === true;
    case "partial_fulfillment":
      return missingItemDetected === true;
    case "not_as_described":
      return notAsDescribedDetected === true || damageDetected === true || wrongItemDetected === true;
    default:
      return null;
  }
})();

const proofContradictsSubtype = (() => {
  if (!proofPresent || !proofAnalysis) return false;
  switch (disputeSubtype) {
    case "damaged_goods":
      return damageDetected === false;
    case "wrong_item":
      return wrongItemDetected === false;
    case "partial_fulfillment":
      return missingItemDetected === false;
    case "not_as_described":
      return notAsDescribedDetected === false && damageDetected === false && wrongItemDetected === false;
    default:
      return false;
  }
})();

// -----------------------------------------------------------------------------
// MATRIX GUARDRAILS
// -----------------------------------------------------------------------------
const allowedResolutionForSubtype = allowedResolutionTypes[disputeSubtype] || new Set(["refund"]);

if (!disputeSubtype) {
  return escalateHuman({
    resolution_type: null,
    reason: "Canonical dispute subtype is missing - manual review required",
    eligible_amount: null,
  });
}

if (!allowedResolutionForSubtype.has(resolvedResolutionType)) {
  return awaitCustomerDecision({
    resolution_type: null,
    reason: `Requested resolution is not allowed for subtype '${disputeSubtype}'`,
    eligible_amount: null,
    invalid_reason_code: "unsupported_resolution_type",
    invalid_reason_detail: `Resolution preference '${requestedResolutionPreference || "unknown"}' is not valid for subtype '${disputeSubtype}'.`,
  });
}

if (resolvedResolutionType === "refund" && priorRefund.exists) {
  return escalateHuman({
    resolution_type: "refund",
    reason: `Duplicate refund risk: ${priorRefund.count} prior refund record(s), total refunded THB ${priorRefund.totalRefunded.toFixed(2)}`,
    eligible_amount: 0,
  });
}

if (!paymentConfirmed) {
  return escalateHuman({
    resolution_type: resolvedResolutionType || "refund",
    reason: `Payment not confirmed (status: ${paymentStatus || "unknown"})`,
    eligible_amount: resolvedResolutionType === "replacement" ? replacementAmount : affectedAmount || totalOrderAmount,
  });
}

if (
  ["non_receipt", "lost"].includes(disputeSubtype) &&
  deliveredEvent
) {
  return escalateHuman({
    resolution_type: resolvedResolutionType,
    reason: "Delivery marked delivered but customer disputes receipt - investigation required",
    tracking_evidence: `Delivered at ${deliveredEvent.location || "unknown"} on ${deliveredEvent.event_time || "unknown"}`,
    eligible_amount: resolvedResolutionType === "replacement" ? replacementAmount : affectedAmount || totalOrderAmount,
  });
}

if (proofRequired && !proofPresent) {
  return awaitCustomerDecision({
    resolution_type: resolvedResolutionType,
    reason: "Required proof was not provided for this dispute type",
    eligible_amount: resolvedResolutionType === "replacement" ? replacementAmount : affectedAmount || totalOrderAmount,
    invalid_reason_code: "insufficient_proof",
    invalid_reason_detail: "This dispute type requires supporting photo evidence before automated triage can proceed.",
  });
}

if (proofRequired && proofAnalysisStatus === "failed") {
  return escalateHuman({
    resolution_type: resolvedResolutionType,
    reason: "Proof analysis failed and requires human review",
    eligible_amount: resolvedResolutionType === "replacement" ? replacementAmount : affectedAmount || totalOrderAmount,
  });
}

if (proofRequired && proofPresent && proofContradictsSubtype) {
  return awaitCustomerDecision({
    resolution_type: resolvedResolutionType,
    reason: "Uploaded proof does not appear to support the reported issue",
    eligible_amount: resolvedResolutionType === "replacement" ? replacementAmount : affectedAmount || totalOrderAmount,
    invalid_reason_code: "proof_contradicts_claim",
    invalid_reason_detail: "The uploaded photos do not appear to support the reported dispute type.",
  });
}

if (proofRequired && proofPresent && proofSupportsSubtype === false) {
  return awaitCustomerDecision({
    resolution_type: resolvedResolutionType,
    reason: "Uploaded proof is currently insufficient to support the reported issue",
    eligible_amount: resolvedResolutionType === "replacement" ? replacementAmount : affectedAmount || totalOrderAmount,
    invalid_reason_code: "insufficient_proof",
    invalid_reason_detail: "The uploaded photos do not provide enough support for the reported dispute type.",
  });
}

// -----------------------------------------------------------------------------
// SUBTYPE ROUTING
// -----------------------------------------------------------------------------
switch (disputeSubtype) {
  case "duplicate_charge": {
    if (totalOrderAmount <= AUTONOMOUS_REFUND_THRESHOLD) {
      return approveExecuting({
        resolution_type: "refund",
        reason: "Duplicate charge refund approved within autonomous threshold",
        eligible_amount: totalOrderAmount,
      });
    }

    return awaitApproval({
      resolution_type: "refund",
      reason: `Duplicate charge refund exceeds autonomous threshold (THB ${totalOrderAmount.toFixed(2)})`,
      eligible_amount: totalOrderAmount,
    });
  }

  case "not_as_described": {
    if (resolvedResolutionType === "replacement") {
      if (!inventoryCheck.feasible) {
        return awaitCustomerDecision({
          resolution_type: "replacement",
          reason: inventoryCheck.reason,
          eligible_amount: replacementAmount,
          invalid_reason_code: "insufficient_inventory",
          invalid_reason_detail: inventoryCheck.reason,
        });
      }

      if (replacementAmount <= AUTONOMOUS_REPLACEMENT_THRESHOLD) {
        return approveExecuting({
          resolution_type: "replacement",
          reason: "Replacement approved: inventory available and amount within autonomous threshold",
          replacement_items: affectedItems,
          affected_item_ids: affectedItemIds,
          eligible_amount: replacementAmount,
        });
      }

      return awaitApproval({
        resolution_type: "replacement",
        reason: `Replacement amount THB ${replacementAmount.toFixed(2)} exceeds autonomous threshold`,
        replacement_items: affectedItems,
        affected_item_ids: affectedItemIds,
        eligible_amount: replacementAmount,
      });
    }

    if (!withinReturnWindow) {
      return awaitCustomerDecision({
        resolution_type: "refund",
        reason: `${daysWindow ?? "Unknown"} days since delivery exceeds 7-day policy window`,
        eligible_amount: affectedAmount || totalOrderAmount,
        invalid_reason_code: "outside_return_window",
        invalid_reason_detail: "This dispute falls outside the applicable refund window.",
      });
    }

    if ((affectedAmount || totalOrderAmount) <= AUTONOMOUS_REFUND_THRESHOLD) {
      return approveExecuting({
        resolution_type: "refund",
        reason: "Refund approved within autonomous threshold",
        eligible_amount: affectedAmount || totalOrderAmount,
      });
    }

    return awaitApproval({
      resolution_type: "refund",
      reason: `Refund amount THB ${(affectedAmount || totalOrderAmount).toFixed(2)} exceeds autonomous threshold`,
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "damaged_goods": {
    if (resolvedResolutionType === "replacement") {
      if (!inventoryCheck.feasible) {
        return awaitCustomerDecision({
          resolution_type: "replacement",
          reason: inventoryCheck.reason,
          eligible_amount: replacementAmount,
          invalid_reason_code: "insufficient_inventory",
          invalid_reason_detail: inventoryCheck.reason,
        });
      }

      if (replacementAmount <= AUTONOMOUS_REPLACEMENT_THRESHOLD) {
        return approveExecuting({
          resolution_type: "replacement",
          reason: "Replacement approved for damaged goods within autonomous threshold",
          replacement_items: affectedItems,
          affected_item_ids: affectedItemIds,
          eligible_amount: replacementAmount,
        });
      }

      return awaitApproval({
        resolution_type: "replacement",
        reason: `Damaged goods replacement exceeds autonomous threshold (THB ${replacementAmount.toFixed(2)})`,
        replacement_items: affectedItems,
        affected_item_ids: affectedItemIds,
        eligible_amount: replacementAmount,
      });
    }

    if (!withinReturnWindow) {
      return awaitCustomerDecision({
        resolution_type: "refund",
        reason: `${daysWindow ?? "Unknown"} days since delivery exceeds 7-day policy window`,
        eligible_amount: affectedAmount || totalOrderAmount,
        invalid_reason_code: "outside_return_window",
        invalid_reason_detail: "This damaged-goods refund falls outside the applicable policy window.",
      });
    }

    if ((affectedAmount || totalOrderAmount) <= AUTONOMOUS_REFUND_THRESHOLD) {
      return approveExecuting({
        resolution_type: "refund",
        reason: "Damaged goods refund approved within autonomous threshold",
        eligible_amount: affectedAmount || totalOrderAmount,
      });
    }

    return awaitApproval({
      resolution_type: "refund",
      reason: `Damaged goods refund exceeds autonomous threshold (THB ${(affectedAmount || totalOrderAmount).toFixed(2)})`,
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "wrong_item": {
    if (resolvedResolutionType === "replacement") {
      if (!inventoryCheck.feasible) {
        return awaitCustomerDecision({
          resolution_type: "replacement",
          reason: inventoryCheck.reason,
          eligible_amount: replacementAmount,
          invalid_reason_code: "insufficient_inventory",
          invalid_reason_detail: inventoryCheck.reason,
        });
      }

      if (replacementAmount <= AUTONOMOUS_REPLACEMENT_THRESHOLD) {
        return approveExecuting({
          resolution_type: "replacement",
          reason: "Wrong-item replacement approved within autonomous threshold",
          replacement_items: affectedItems,
          affected_item_ids: affectedItemIds,
          eligible_amount: replacementAmount,
        });
      }

      return awaitApproval({
        resolution_type: "replacement",
        reason: `Wrong-item replacement exceeds autonomous threshold (THB ${replacementAmount.toFixed(2)})`,
        replacement_items: affectedItems,
        affected_item_ids: affectedItemIds,
        eligible_amount: replacementAmount,
      });
    }

    if (!withinReturnWindow) {
      return awaitCustomerDecision({
        resolution_type: "refund",
        reason: `${daysWindow ?? "Unknown"} days since delivery exceeds 7-day policy window`,
        eligible_amount: affectedAmount || totalOrderAmount,
        invalid_reason_code: "outside_return_window",
        invalid_reason_detail: "This wrong-item refund falls outside the applicable policy window.",
      });
    }

    if ((affectedAmount || totalOrderAmount) <= AUTONOMOUS_REFUND_THRESHOLD) {
      return approveExecuting({
        resolution_type: "refund",
        reason: "Wrong-item refund approved within autonomous threshold",
        eligible_amount: affectedAmount || totalOrderAmount,
      });
    }

    return awaitApproval({
      resolution_type: "refund",
      reason: `Wrong-item refund exceeds autonomous threshold (THB ${(affectedAmount || totalOrderAmount).toFixed(2)})`,
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "partial_fulfillment": {
    return escalateHuman({
      resolution_type: "refund",
      reason: "Partial fulfillment requires human review per decision matrix",
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "return_request":
  case "changed_mind": {
    if (!orderStatusEligible) {
      return awaitCustomerDecision({
        resolution_type: "return",
        reason: `Order status '${orderStatus || "unknown"}' is not eligible for return`,
        eligible_amount: totalOrderAmount,
        invalid_reason_code: "non_returnable_item",
        invalid_reason_detail: `Order status '${orderStatus || "unknown"}' is not eligible for return processing.`,
      });
    }

    if (!withinReturnWindow) {
      return awaitCustomerDecision({
        resolution_type: "return",
        reason: `${daysWindow ?? "Unknown"} days since delivery exceeds 7-day policy window`,
        eligible_amount: totalOrderAmount,
        invalid_reason_code: "outside_return_window",
        invalid_reason_detail: "This return request falls outside the applicable return window.",
      });
    }

    return awaitApproval({
      resolution_type: "return",
      reason: "Return request requires approval and inspection; returns are never autonomous",
      eligible_amount: totalOrderAmount,
    });
  }

  case "other": {
    return escalateHuman({
      resolution_type: "refund",
      reason: "Uncategorized dispute requires human review",
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "non_receipt": {
    if (resolvedResolutionType === "replacement") {
      if (!inventoryCheck.feasible) {
        return awaitCustomerDecision({
          resolution_type: "replacement",
          reason: inventoryCheck.reason,
          eligible_amount: replacementAmount,
          invalid_reason_code: "insufficient_inventory",
          invalid_reason_detail: inventoryCheck.reason,
        });
      }

      return awaitApproval({
        resolution_type: "replacement",
        reason: "Non-receipt replacement requires approval",
        replacement_items: affectedItems,
        affected_item_ids: affectedItemIds,
        eligible_amount: replacementAmount,
      });
    }

    if (exceptionEvent && !deliveredEvent) {
      const refundAmount = affectedAmount || totalOrderAmount;
      if (refundAmount <= AUTONOMOUS_REFUND_THRESHOLD) {
        return approveExecuting({
          resolution_type: "refund",
          reason: "Carrier exception detected before delivery; refund approved within autonomous threshold",
          tracking_evidence: `Exception event: ${exceptionEvent.event_type || "unknown"} at ${exceptionEvent.location || "unknown"}`,
          eligible_amount: refundAmount,
        });
      }

      return awaitApproval({
        resolution_type: "refund",
        reason: `Carrier exception refund exceeds autonomous threshold (THB ${refundAmount.toFixed(2)})`,
        tracking_evidence: `Exception event: ${exceptionEvent.event_type || "unknown"} at ${exceptionEvent.location || "unknown"}`,
        eligible_amount: refundAmount,
      });
    }

    const daysInTransit = daysSince(inTransitEvent?.event_time);
    if (inTransitEvent && !deliveredEvent && daysInTransit != null && daysInTransit > 7) {
      const refundAmount = affectedAmount || totalOrderAmount;
      if (refundAmount <= AUTONOMOUS_REFUND_THRESHOLD) {
        return approveExecuting({
          resolution_type: "refund",
          reason: `Package has been in transit for ${daysInTransit} days; refund approved within autonomous threshold`,
          tracking_evidence: `Last tracking update: in_transit on ${inTransitEvent.event_time || "unknown"}`,
          eligible_amount: refundAmount,
        });
      }

      return awaitApproval({
        resolution_type: "refund",
        reason: `In-transit non-receipt refund exceeds autonomous threshold (THB ${refundAmount.toFixed(2)})`,
        tracking_evidence: `Last tracking update: in_transit on ${inTransitEvent.event_time || "unknown"}`,
        eligible_amount: refundAmount,
      });
    }

    return escalateHuman({
      resolution_type: "refund",
      reason: "Non-receipt requires human investigation",
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "delayed": {
    const deliveredAt =
      deliveredEvent?.event_time ||
      orderData.delivered_at ||
      orderData.fulfilled_at ||
      null;
    const estimatedDelivery =
      deliveryFacts.estimated_delivery ||
      shipmentData.estimated_delivery ||
      null;

    const overdueDays =
      deliveredAt && estimatedDelivery
        ? daysBetween(estimatedDelivery, deliveredAt)
        : null;

    if (overdueDays != null && overdueDays > 3) {
      if (shippingFee <= AUTONOMOUS_REFUND_THRESHOLD) {
        return approveExecuting({
          resolution_type: "refund",
          reason: "Delivery SLA breached; shipping-fee refund approved",
          shipping_fee_refund_only: true,
          eligible_amount: shippingFee,
        });
      }

      return awaitApproval({
        resolution_type: "refund",
        reason: `Delivery SLA shipping-fee refund exceeds autonomous threshold (THB ${shippingFee.toFixed(2)})`,
        shipping_fee_refund_only: true,
        eligible_amount: shippingFee,
      });
    }

    if (exceptionEvent && !deliveredEvent) {
      const refundAmount = affectedAmount || totalOrderAmount;
      if (refundAmount <= AUTONOMOUS_REFUND_THRESHOLD) {
        return approveExecuting({
          resolution_type: "refund",
          reason: "Carrier exception detected before delivery; refund approved within autonomous threshold",
          tracking_evidence: `Exception event: ${exceptionEvent.event_type || "unknown"} at ${exceptionEvent.location || "unknown"}`,
          eligible_amount: refundAmount,
        });
      }

      return awaitApproval({
        resolution_type: "refund",
        reason: `Carrier exception refund exceeds autonomous threshold (THB ${refundAmount.toFixed(2)})`,
        tracking_evidence: `Exception event: ${exceptionEvent.event_type || "unknown"} at ${exceptionEvent.location || "unknown"}`,
        eligible_amount: refundAmount,
      });
    }

    const daysInTransit = daysSince(inTransitEvent?.event_time);
    if (inTransitEvent && !deliveredEvent && daysInTransit != null && daysInTransit > 7) {
      const refundAmount = affectedAmount || totalOrderAmount;
      if (refundAmount <= AUTONOMOUS_REFUND_THRESHOLD) {
        return approveExecuting({
          resolution_type: "refund",
          reason: `Package has been in transit for ${daysInTransit} days; refund approved within autonomous threshold`,
          tracking_evidence: `Last tracking update: in_transit on ${inTransitEvent.event_time || "unknown"}`,
          eligible_amount: refundAmount,
        });
      }

      return awaitApproval({
        resolution_type: "refund",
        reason: `In-transit delay refund exceeds autonomous threshold (THB ${refundAmount.toFixed(2)})`,
        tracking_evidence: `Last tracking update: in_transit on ${inTransitEvent.event_time || "unknown"}`,
        eligible_amount: refundAmount,
      });
    }

    return escalateHuman({
      resolution_type: "refund",
      reason: "Delivery delay does not yet satisfy deterministic approval conditions",
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "exception": {
    if (exceptionEvent && !deliveredEvent) {
      const refundAmount = affectedAmount || totalOrderAmount;
      if (refundAmount <= AUTONOMOUS_REFUND_THRESHOLD) {
        return approveExecuting({
          resolution_type: "refund",
          reason: "Carrier exception detected before delivery; refund approved within autonomous threshold",
          tracking_evidence: `Exception event: ${exceptionEvent.event_type || "unknown"} at ${exceptionEvent.location || "unknown"}`,
          eligible_amount: refundAmount,
        });
      }

      return awaitApproval({
        resolution_type: "refund",
        reason: `Carrier exception refund exceeds autonomous threshold (THB ${refundAmount.toFixed(2)})`,
        tracking_evidence: `Exception event: ${exceptionEvent.event_type || "unknown"} at ${exceptionEvent.location || "unknown"}`,
        eligible_amount: refundAmount,
      });
    }

    return escalateHuman({
      resolution_type: "refund",
      reason: "Carrier exception requires human review",
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }

  case "lost": {
    if (resolvedResolutionType === "replacement") {
      if (!inventoryCheck.feasible) {
        return awaitCustomerDecision({
          resolution_type: "replacement",
          reason: inventoryCheck.reason,
          eligible_amount: replacementAmount,
          invalid_reason_code: "insufficient_inventory",
          invalid_reason_detail: inventoryCheck.reason,
        });
      }

      return awaitApproval({
        resolution_type: "replacement",
        reason: "Lost-package replacement requires approval",
        replacement_items: affectedItems,
        affected_item_ids: affectedItemIds,
        eligible_amount: replacementAmount,
      });
    }

    if (lostEvent && !deliveredEvent) {
      const refundAmount = affectedAmount || totalOrderAmount;
      if (refundAmount <= AUTONOMOUS_REFUND_THRESHOLD) {
        return approveExecuting({
          resolution_type: "refund",
          reason: "Lost-package refund approved within autonomous threshold",
          tracking_evidence: `Lost event at ${lostEvent.location || "unknown"} on ${lostEvent.event_time || "unknown"}`,
          eligible_amount: refundAmount,
        });
      }

      return awaitApproval({
        resolution_type: "refund",
        reason: `Lost-package refund exceeds autonomous threshold (THB ${refundAmount.toFixed(2)})`,
        tracking_evidence: `Lost event at ${lostEvent.location || "unknown"} on ${lostEvent.event_time || "unknown"}`,
        eligible_amount: refundAmount,
      });
    }

    return escalateHuman({
      resolution_type: resolvedResolutionType,
      reason: "Lost-package claim requires human investigation",
      eligible_amount: resolvedResolutionType === "replacement" ? replacementAmount : affectedAmount || totalOrderAmount,
    });
  }

  default: {
    return escalateHuman({
      resolution_type: "refund",
      reason: `Unsupported canonical subtype '${disputeSubtype || "unknown"}' requires manual review`,
      eligible_amount: affectedAmount || totalOrderAmount,
    });
  }
}

return [{
  case_id: $json.case_id,
  status: "approved_executing",
  resolution_path: "autonomous",
  triage_decision: {
    triage_decision: $json.triage_decision,
    resolution_type: $json.resolution_type,
    reason: $json.reason,
    eligible_amount: $json.eligible_amount,
    tracking_evidence: $json.tracking_evidence ?? null,
    replacement_items: $json.replacement_items ?? null,
    requires_human_review: false
  }
}];

return [{
  case_id: $json.case_id,
  status: "awaiting_approval",
  resolution_path: "approval",
  triage_decision: {
    triage_decision: $json.triage_decision || "awaiting_approval",
    resolution_type: $json.resolution_type || null,
    reason: $json.reason || "",
    eligible_amount: $json.eligible_amount ?? null,
    tracking_evidence: $json.tracking_evidence ?? null,
    replacement_items: $json.replacement_items ?? null,
    requires_human_review: true
  }
}];

return [{
  case_id: $json.case_id,
  status: "escalated_human_required",
  resolution_path: "escalation",
  triage_decision: {
    triage_decision: $json.triage_decision || "escalation",
    resolution_type: $json.resolution_type || null,
    reason: $json.reason || "",
    eligible_amount: $json.eligible_amount ?? null,
    tracking_evidence: $json.tracking_evidence ?? null,
    replacement_items: $json.replacement_items ?? null,
    requires_human_review: true
  }
}];

return [{
  case_id: $json.case_id,
  status: "awaiting_approval",
  resolution_path: "approval",
  triage_decision: {
    triage_decision: $json.triage_decision || "awaiting_approval",
    resolution_type: $json.resolution_type || null,
    reason: $json.reason || "",
    eligible_amount: $json.eligible_amount ?? null,
    tracking_evidence: $json.tracking_evidence ?? null,
    replacement_items: $json.replacement_items ?? null,
    requires_human_review: true
  }
}];
